import React, { useEffect, useState, useRef } from "react";
import { useLocation } from "react-router-dom";
import { Calendar } from "primereact/calendar";
import { MultiSelect } from "primereact/multiselect";
import axios from "axios";
import moment from "moment";
import { Button } from "primereact/button";
import Combinedgraph from "../graphs/combinedgraph";
import { InputSwitch } from "primereact/inputswitch";
import { InputNumber } from "primereact/inputnumber";
import { Checkbox } from "primereact/checkbox";
import { Dropdown } from "primereact/dropdown";
import jwt_decode from "jwt-decode";
import { useTheme } from "../context/ThemeContext";
import { Toast } from 'primereact/toast';
import { exportSingleGraphToExcel } from "./_excelUtils";
import "../cssFiles/pageCommon.css";

export default function Combined() {
    const { isDarkMode } = useTheme();
    const search = useLocation().search;
    const id = new URLSearchParams(search).get("token");
    const [pageHide, setPageHide] = useState(true);
    const [isLoading, setIsLoading] = useState(false);
    const [graphenable, setGraphenable] = useState(true);

    const [dateRange, setDateRange] = useState([
        moment().startOf("day").subtract(2, "day").toDate(),
        moment().endOf("day").subtract(2, "day").toDate()
    ]);
    const [minutes, setMinutes] = useState(1);

    // States list
    const [fStates, setFStates] = useState([]);
    const [vStates, setVStates] = useState([]);
    const [dStates, setDStates] = useState([]);
    const [iStates, setIStates] = useState([]);
    const [lStates, setLStates] = useState([]);

    // Selected
    const [selectedFStates, setSelectedFStates] = useState([]);
    const [selectedVStates, setSelectedVStates] = useState([]);
    const [selectedDStates, setSelectedDStates] = useState([]);
    const [selectedIStates, setSelectedIStates] = useState([]);
    const [selectedLStates, setSelectedLStates] = useState([]);

    // Data
    const [frequencyData, setFrequencyData] = useState(null);
    const [voltageData, setVoltageData] = useState(null);
    const [demandData, setDemandData] = useState(null);
    const [ictData, setIctData] = useState(null);
    const [linesData, setLinesData] = useState(null);

    // Checks
    const [checkedF, setCheckedF] = useState(false);
    const [checkedV, setCheckedV] = useState(false);
    const [checkedD, setCheckedD] = useState(false);
    const [checkedI, setCheckedI] = useState(false);
    const [checkedL, setCheckedL] = useState(false);

    const [durationRegion, setDurationRegion] = useState([]);
    const toast = useRef(null);

    const names = {
        BH_DEMAND: "Bihar DEMAND",
        DVC_DEMAND: "DVC DEMAND",
        GR_DEMAND: "Odisha DEMAND",
        JH_DEMAND: "Jharkhand DEMAND",
        "REG DEMAND": "Regional DEMAND",
        SI_DEMAND: "Sikkim DEMAND",
        WB_DEMAND: "West Bengal DEMAND",
    };

    useEffect(() => {
        if (id) {
            axios.get("https://sso.erldc.in:5000/verify", { headers: { Token: id } })
                .then(res => {
                    const decoded = jwt_decode(res.data["Final_Token"], "it@posoco");
                    setPageHide(!decoded("Login"));
                }).catch(() => {});
        } else {
            setPageHide(true);
        }

        if (checkedV && checkedD) {
            alert("Voltage & Demand Comparison is not allowed. Please select one");
            setCheckedV(!checkedD);
            setCheckedD(!checkedV);
        }
    }, [id, checkedV, checkedD]);

    useEffect(() => {
        if (dateRange && dateRange[0] && dateRange[1]) {
            const sDate = moment(dateRange[0]).format("YYYY-MM-DD");
            const eDate = moment(dateRange[1]).format("YYYY-MM-DD");

            if (checkedF) axios.post(`/FrequencyNames?startDate=${sDate}&endDate=${eDate}`).then(res => setFStates(res.data)).catch(() => {});
            if (checkedV) axios.post(`/VoltageNames?startDate=${sDate}&endDate=${eDate}`).then(res => setVStates(res.data)).catch(() => {});
            if (checkedD) axios.post(`/DemandMinNames?startDate=${sDate}&endDate=${eDate}`).then(res => {
                setDStates(res.data.map(v => ({ label: names[v] || v, value: v })));
            }).catch(() => {});
            if (checkedI) axios.post(`/ICTNames?startDate=${sDate}&endDate=${eDate}`).then(res => setIStates(res.data)).catch(() => {});
            if (checkedL) axios.post(`/LinesMWMVARNames?startDate=${sDate}&endDate=${eDate}`).then(res => {
                setLStates(res.data.map(v => ({ label: v.split(" Ckt-").join(" ").split(":")[0] + " " + (v.split(" end ")[1] || ""), value: v })));
            }).catch(() => {});
        }
    }, [dateRange, checkedF, checkedV, checkedD, checkedI, checkedL]);

    const frequencyRegionChange = (e) => {
        let selected = [...durationRegion];
        if (e.checked) selected.push(e.value);
        else selected.splice(selected.indexOf(e.value), 1);
        setDurationRegion(selected);
    };

    const getCombinedData = async () => {
        if (dateRange && dateRange[0] && dateRange[1]) {
            setIsLoading(true);
            const sDate = moment(dateRange[0]).format("YYYY-MM-DD");
            const eDate = moment(dateRange[1]).format("YYYY-MM-DD");
            
            try {
                if (checkedF && selectedFStates.length) {
                    const res = await axios.post(`/GetFrequencyData?startDate=${sDate}&endDate=${eDate}&stationName=${selectedFStates}&time=${minutes}`);
                    if (res.data === "Time ERROR") { alert("Data Interval shouldn't be more than time value"); setIsLoading(false); return; }
                    setFrequencyData(res.data);
                }
                if (checkedV && selectedVStates.length) {
                    const res = await axios.post(`/GetVoltageData?startDate=${sDate}&endDate=${eDate}&stationName=${selectedVStates}&time=${minutes}`);
                    if (res.data === "Time ERROR") { alert("Interval Error"); setIsLoading(false); return; }
                    setVoltageData(res.data);
                }
                if (checkedD && selectedDStates.length) {
                    const res = await axios.post(`/GetDemandMinData?startDate=${sDate}&endDate=${eDate}&stationName=${selectedDStates}&time=${minutes}`);
                    if (res.data === "Time ERROR") { alert("Interval Error"); setIsLoading(false); return; }
                    setDemandData(res.data);
                }
                if (checkedI && selectedIStates.length) {
                    let cleanStates = selectedIStates.map(s => s.replace(/&/g, "%26")).join(",");
                    const res = await axios.post(`/GetICTData?startDate=${sDate}&endDate=${eDate}&stationName=${cleanStates}&time=${minutes}`);
                    if (res.data === "Time ERROR") { alert("Interval Error"); setIsLoading(false); return; }
                    setIctData(res.data);
                }
                if (checkedL && selectedLStates.length) {
                    const res = await axios.post(`/LinesMWMVARData?startDate=${sDate}&endDate=${eDate}&stationName=${selectedLStates}&time=${minutes}`);
                    if (res.data === "Time ERROR") { alert("Interval Error"); setIsLoading(false); return; }
                    setLinesData(res.data);
                }
                
                setTimeout(() => setGraphenable(false), 500);
            } catch (err) { console.error(err); }
            setIsLoading(false);
        }
    };

    const graph_list = {
        Frequency: frequencyData,
        Voltage: voltageData,
        Demand: demandData,
        ICT: ictData,
        Lines: linesData,
    };

    // Very simple pseudo-export that downloads whichever active data sets exist
    const handleExport = () => {
        // Pick whichever data was fetched to act as export basis
        let exData = null;
        let pName = "Combined";
        if (frequencyData) { exData = frequencyData; pName = "Frequency_Combined"; }
        else if (voltageData) { exData = voltageData; pName = "Voltage_Combined"; }
        else if (demandData) { exData = demandData; pName = "Demand_Combined"; }
        else if (linesData) { exData = linesData; pName = "Lines_Combined"; }
        else if (ictData) { exData = ictData; pName = "ICT_Combined"; }
        
        if (exData) exportSingleGraphToExcel(exData, pName);
    };

    return (
        <div style={{ padding: "0 10px" }}>
            <Toast ref={toast} />
            {isLoading && (
                <div className="pc-loading-overlay">
                    <div className="pc-loading-box">
                        <div className="pc-spinner"></div>
                        <div style={{ color: "#1e293b", fontWeight: 700, fontSize: "14px", fontFamily: "Inter" }}>Loading Analytics</div>
                        <div style={{ color: "#64748b", fontSize: "11px", marginTop: "4px" }}>Synthesizing combined metrics...</div>
                    </div>
                </div>
            )}

            <div className="pc-hero">
                <div className="pc-hero-inner">
                    <div className="pc-hero-icon"><i className="pi pi-briefcase" style={{ color: "#f59e0b", fontSize: "20px" }}></i></div>
                    <div className="pc-hero-text">
                        <div className="pc-hero-badge" style={{ borderColor: "rgba(245,158,11,0.5)", color: "#fcd34d" }}>Combined Intelligence</div>
                        <h1 className="pc-hero-title">Multi-Disciplinary Analytics</h1>
                        <p className="pc-hero-sub">Overlay frequency, demand, voltage, and flow metrics</p>
                    </div>
                </div>
            </div>

            <div className="pc-section">
                <div className="pc-section-head">
                    <div className="pc-section-pill" style={{ background: "rgba(245,158,11,0.1)", color: "#f59e0b" }}><i className="pi pi-filter-fill"></i></div>
                    <span className="pc-section-title">Global Analysis Config</span>
                </div>
                <div className="pc-section-body p-fluid grid formgrid">
                    <div className="field col-12 md:col-6">
                        <label className="pc-label"><i className="pi pi-calendar"></i> Date Range</label>
                        <Calendar selectionMode="range" readOnlyInput hideOnRangeSelection placeholder="Select Range"
                            dateFormat="dd-M-yy" value={dateRange} onChange={(e) => setDateRange(e.value)}
                            showIcon className="w-full" />
                    </div>
                    <div className="field col-12 md:col-6">
                        <label className="pc-label"><i className="pi pi-sliders-h"></i> Resolution Setting</label>
                        <div className="pc-interval-row">
                            <span className="pc-interval-lbl">Data Interval (Min)</span>
                            <InputNumber min={1} max={1440} value={minutes} onValueChange={(e) => setMinutes(e.value)} 
                                showButtons buttonLayout="horizontal" decrementButtonClassName="p-button-danger" incrementButtonClassName="p-button-success" />
                        </div>
                    </div>
                </div>

                <div className="pc-section-body grid p-0 mt-3" style={{ borderTop: "1px solid var(--pc-border)" }}>
                    {/* FREQUENCY */}
                    <div className="col-12 md:col-4 p-3 border-right-1" style={{ borderColor: "var(--pc-border)" }}>
                        <div className="flex align-items-center justify-content-between mb-2">
                            <label className="pc-label m-0 font-bold"><i className="pi pi-chart-line text-purple-500"></i> Frequency</label>
                            <InputSwitch checked={checkedF} onChange={(e) => setCheckedF(e.value)} />
                        </div>
                        <MultiSelect display="chip" placeholder="Select Bus" value={selectedFStates} options={fStates} onChange={(e) => setSelectedFStates(e.value)} filter disabled={!checkedF} className="pc-multiselect" />
                    </div>

                    {/* VOLTAGE */}
                    <div className="col-12 md:col-4 p-3 border-right-1" style={{ borderColor: "var(--pc-border)" }}>
                        <div className="flex align-items-center justify-content-between mb-2">
                            <label className="pc-label m-0 font-bold"><i className="pi pi-bolt text-yellow-500"></i> Voltage</label>
                            <InputSwitch checked={checkedV} onChange={(e) => setCheckedV(e.value)} />
                        </div>
                        <MultiSelect display="chip" placeholder="Select Bus" value={selectedVStates} options={vStates} onChange={(e) => setSelectedVStates(e.value)} filter disabled={!checkedV} className="pc-multiselect" />
                    </div>

                    {/* DEMAND */}
                    <div className="col-12 md:col-4 p-3">
                        <div className="flex align-items-center justify-content-between mb-2">
                            <label className="pc-label m-0 font-bold"><i className="pi pi-chart-bar text-cyan-500"></i> Demand</label>
                            <InputSwitch checked={checkedD} onChange={(e) => setCheckedD(e.value)} />
                        </div>
                        <MultiSelect display="chip" placeholder="Select Region" value={selectedDStates} options={dStates} onChange={(e) => setSelectedDStates(e.value)} filter disabled={!checkedD} className="pc-multiselect" />
                    </div>

                    {/* ICT */}
                    <div className="col-12 md:col-6 p-3 border-top-1 border-right-1" style={{ borderColor: "var(--pc-border)" }}>
                        <div className="flex align-items-center justify-content-between mb-2">
                            <label className="pc-label m-0 font-bold"><i className="pi pi-directions-alt text-red-400"></i> Interconnectors (ICT)</label>
                            <InputSwitch checked={checkedI} onChange={(e) => setCheckedI(e.value)} />
                        </div>
                        <MultiSelect display="chip" placeholder="Select ICT" value={selectedIStates} options={iStates} onChange={(e) => setSelectedIStates(e.value)} filter disabled={!checkedI} className="pc-multiselect" />
                    </div>

                    {/* Lines */}
                    <div className="col-12 md:col-6 p-3 border-top-1" style={{ borderColor: "var(--pc-border)" }}>
                        <div className="flex align-items-center justify-content-between mb-2">
                            <label className="pc-label m-0 font-bold"><i className="pi pi-arrow-right-arrow-left text-green-500"></i> Lines MW/MVAR</label>
                            <InputSwitch checked={checkedL} onChange={(e) => setCheckedL(e.value)} />
                        </div>
                        <MultiSelect display="chip" placeholder="Select Line" value={selectedLStates} options={lStates} onChange={(e) => setSelectedLStates(e.value)} filter disabled={!checkedL} className="pc-multiselect" />
                    </div>
                </div>
            </div>

            <div className="pc-section p-3 flex align-items-center justify-content-between">
                <div className="pc-freq-row">
                    <span className="pc-freq-title">Duration Overlay:</span>
                    <Checkbox inputId="dr1" value="Frequency" onChange={frequencyRegionChange} checked={durationRegion.includes("Frequency")} /> <label htmlFor="dr1">Frq</label>
                    <Checkbox inputId="dr2" value="Voltage" onChange={frequencyRegionChange} checked={durationRegion.includes("Voltage")} /> <label htmlFor="dr2">Vlg</label>
                    <Checkbox inputId="dr3" value="Demand" onChange={frequencyRegionChange} checked={durationRegion.includes("Demand")} /> <label htmlFor="dr3">Dem</label>
                </div>
                <div className="flex gap-2 w-4">
                    <Button label="Synthesize Data" icon="pi pi-bolt" className="pc-btn-primary flex-1" onClick={getCombinedData} />
                    {!graphenable && <Button icon="pi pi-file-excel" className="pc-btn-excel" onClick={handleExport} />}
                </div>
            </div>

            {!graphenable && (
                <div className="pc-chart-wrapper">
                    <div className="pc-chart-title"><i className="pi pi-chart-pie" style={{ color: "#f59e0b" }}></i> Synthesized Correlation Graph</div>
                    <Combinedgraph
                        graph_list={graph_list}
                        duration_region={durationRegion}
                        checkedL={checkedL} checkedI={checkedI} checkedD={checkedD} checkedV={checkedV} checkedF={checkedF}
                        Selected_i_states={selectedIStates} Selected_l_states={selectedLStates}
                    />
                </div>
            )}
            
        </div>
    );
}
